// ─── 4-Block Zone Structure ───────────────────────────────────────────────────
//
//   // @auto-generated by SilentSpec | YYYY-MM-DD
//   // Source: foo.ts
//   // Functions covered: fn1, fn2, ...
//
//   // <SS-IMPORTS-START>      ← SYSTEM: all imports, replaced every run
//   // <SS-IMPORTS-END>
//
//   // <SS-HELPERS-START>      ← SYSTEM: helper factories, replaced every run
//   // <SS-HELPERS-END>
//
//   // <SS-USER-TESTS>         ← USER: never touched after creation
//   // </SS-USER-TESTS>
//
//   // <SS-GENERATED-START>    ← SYSTEM: AI test blocks, replaced every run
//   // <SS-GENERATED-END>
//
// System zones are fully replaced each run — single source of truth, no dedup needed.
// User zone is written once and never modified again.

const SS_IMPORTS_START = '// <SS-IMPORTS-START>';
const SS_IMPORTS_END   = '// <SS-IMPORTS-END>';
const SS_HELPERS_START = '// <SS-HELPERS-START>';
const SS_HELPERS_END   = '// <SS-HELPERS-END>';
const SS_USER_START    = '// <SS-USER-TESTS>';
const SS_USER_END      = '// </SS-USER-TESTS>';

const SS_USER_PLACEHOLDER = '// Add your own tests here — SilentSpec will never modify this section';

const TEST_DIRS = ['__tests__', 'tests', 'test', 'specs'];

export interface SpecPathResolution {
  specPath: string;
  companionPath?: string;
  reason:
    | 'existing-managed'
    | 'existing-managed-ancestor'
    | 'existing-managed-sister'
    | 'new-established-dir'
    | 'new-fallback'
    | 'new-sister-for-unmanaged';
}

// ─── Unmanaged-spec detection ─────────────────────────────────────────────────
// isUnmanagedContent and isUnmanagedSpec live in utils/unmanagedSpec.ts so they
// have no vscode dependency and can be unit-tested with plain strings.
export { isUnmanagedContent, isUnmanagedSpec } from './utils/unmanagedSpec';

// ─── Header ───────────────────────────────────────────────────────────────────

function buildHeader(sourcePath?: string, exportedFunctions?: string[], companionPath?: string): string {
  const date = new Date().toISOString().split('T')[0];
  const workspaceFolder = sourcePath
    ? vscode.workspace.getWorkspaceFolder(vscode.Uri.file(sourcePath))
    : undefined;
  const workspaceRoot = workspaceFolder?.uri.fsPath;
  const sourceDisplay = (workspaceRoot && sourcePath)
    ? path.relative(workspaceRoot, sourcePath)
    : sourcePath ? path.basename(sourcePath) : '';
  const sourceNote = sourceDisplay ? `\n// Source: ${sourceDisplay}` : '';
  const companionNote = companionPath
    ? `\n// Companion to: ${path.basename(companionPath)} (hand-written - never modified by SilentSpec)`
    : '';
  const fnNote = exportedFunctions && exportedFunctions.length > 0
    ? `\n// Functions covered: ${exportedFunctions.join(', ')}`
    : '';
  return `// @auto-generated by SilentSpec | ${date}${sourceNote}${companionNote}${fnNote}`;
}

// ─── Structure helpers ────────────────────────────────────────────────────────

function hasFullStructure(content: string): boolean {
  return (
    content.includes(SS_IMPORTS_START) &&
    content.includes(SS_IMPORTS_END) &&
    content.includes(SS_HELPERS_START) &&
    content.includes(SS_HELPERS_END) &&
    content.includes(SS_USER_START) &&
    content.includes(SS_USER_END) &&
    content.includes(SS_START_PREFIX) &&
    content.includes(SS_END)
  );
}

function validateSSStructure(content: string): string | null {
  const startIdx = content.indexOf(SS_START_PREFIX);
  const endIdx   = content.indexOf(SS_END);
  if (startIdx === -1 && endIdx === -1) { return null; }
  if (startIdx === -1) { return 'SS-GENERATED-START missing'; }
  if (endIdx === -1)   { return 'SS-GENERATED-END missing'; }
  if (startIdx >= endIdx) { return 'SS-GENERATED-START after SS-GENERATED-END'; }
  if (content.split(SS_START_PREFIX).length - 1 > 1) { return 'duplicate SS-GENERATED-START'; }
  if (content.split(SS_END).length - 1 > 1)          { return 'duplicate SS-GENERATED-END'; }
  return null;
}

// ─── File assembly ────────────────────────────────────────────────────────────

function buildFullFile(
  importsBlock: string,
  helpersBlock: string,
  userTests: string,
  generatedBlock: string,
  sourcePath?: string,
  exportedFunctions?: string[],
  companionPath?: string
): string {
  return [
    buildHeader(sourcePath, exportedFunctions, companionPath),
    '',
    SS_IMPORTS_START,
    importsBlock,
    SS_IMPORTS_END,
    '',
    SS_HELPERS_START,
    helpersBlock,
    SS_HELPERS_END,
    '',
    SS_USER_START,
    userTests,
    SS_USER_END,
    '',
    generatedBlock,
  ].join('\n').replace(/\n{3,}/g, '\n\n') + '\n';
}

// ─── System zone replacement (Case 2) ────────────────────────────────────────

function replaceSystemZones(
  existing: string,
  importsBlock: string,
  helpersBlock: string,
  log: (msg: string) => void
): string | null {
  // Duplicate markers → abort the entire write, not just the zone update.
  // Returning null signals to the caller to skip the write entirely.
  if (existing.split(SS_IMPORTS_START).length - 1 > 1 ||
      existing.split(SS_IMPORTS_END).length - 1 > 1) {
    log('Warning: duplicate SS-IMPORTS markers detected — aborting write to prevent corruption');
    void vscode.window.showWarningMessage('SilentSpec: Duplicate zone markers found. Delete the spec file and re-save to regenerate.');
    return null;
  }
  if (existing.split(SS_HELPERS_START).length - 1 > 1 ||
      existing.split(SS_HELPERS_END).length - 1 > 1) {
    log('Warning: duplicate SS-HELPERS markers detected — aborting write to prevent corruption');
    void vscode.window.showWarningMessage('SilentSpec: Duplicate zone markers found. Delete the spec file and re-save to regenerate.');
    return null;
  }

  let result = existing;

  const importsStart = result.indexOf(SS_IMPORTS_START);
  const importsEnd   = result.indexOf(SS_IMPORTS_END);
  if (importsStart !== -1 && importsEnd !== -1 && importsStart < importsEnd) {
    result =
      result.slice(0, importsStart) +
      SS_IMPORTS_START + '\n' + importsBlock + '\n' + SS_IMPORTS_END +
      result.slice(importsEnd + SS_IMPORTS_END.length);
  }

  const helpersStart = result.indexOf(SS_HELPERS_START);
  const helpersEnd   = result.indexOf(SS_HELPERS_END);
  if (helpersStart !== -1 && helpersEnd !== -1 && helpersStart < helpersEnd) {
    result =
      result.slice(0, helpersStart) +
      SS_HELPERS_START + '\n' + helpersBlock + '\n' + SS_HELPERS_END +
      result.slice(helpersEnd + SS_HELPERS_END.length);
  }

  return result;
}

// ─── Local model/enum mock filter ─────────────────────────────────────────────
//
// TypeScript erases model/type/enum/constants files at compile time.
// Mocking them removes enum values and silently breaks all assertions.
// These patterns match typical "no-mock" file names used in the wild.

const LOCAL_MODEL_SEGMENT_RE = /^(models?|types?|enums?|constants?|dtos?|entities|entity|interfaces?|schemas?)$/i;
const LOCAL_MODEL_SUFFIX_RE  = /\.(model|type|enum|constant|dto|entity|interface|schema)$/i;

function isLocalModelMockPath(mockPath: string): boolean {
  if (!mockPath.startsWith('.')) { return false; }
  const lastSegment = (mockPath.split('/').pop() ?? '').replace(/\.[tj]sx?$/, '');
  return LOCAL_MODEL_SEGMENT_RE.test(lastSegment) || LOCAL_MODEL_SUFFIX_RE.test(lastSegment);
}

// ─── Import dedup by module path (Case 3 migration only) ─────────────────────
//
// During migration we merge user's existing imports with AI imports.
// Rules:
//   - If a module path (normalized to absolute) already exists in the base set,
//     skip it from additions — the base version is kept as-is.
//   - vi/jest.mock() calls for local model/type/enum/constants files are dropped.
//   - vi/jest.mock() calls for other paths are deduplicated by mock path.
//
// specDir is used to resolve relative paths to absolute for comparison, so
// '../models' and '../../models' that resolve to the same file are treated as equal.
// Secondary basename dedup: two relative imports with the same basename are treated
// as the same module (catches '../models' vs '../../models' across dir boundaries).

function mergeImportBlocks(base: string, additions: string, specDir: string, log?: (msg: string) => void): string {
  const seenPaths     = new Set<string>();
  const seenBasenames = new Set<string>();  // secondary: basename of relative imports
  const seenMockPaths = new Set<string>();
  const resultLines: string[] = [];
  // Maps normalized module path → resultLines index for single-line base imports.
  // Used to merge addition specifiers in-place rather than dropping them.
  const baseImportAt  = new Map<string, number>();

  function normalizeModulePath(modulePath: string): string {
    return modulePath.startsWith('.') ? path.resolve(specDir, modulePath) : modulePath;
  }

  function relativeBasename(modulePath: string): string | null {
    if (!modulePath.startsWith('.')) { return null; }
    return path.basename(modulePath).replace(/\.[tj]sx?$/, '');
  }

  // Parse a single-line import into its structural parts.
  // Returns null for multiline or unrecognised forms.
  function parseSingleLineImport(line: string): {
    typeOnly: boolean; isNamespace: boolean; isSideEffect: boolean;
    defaultImport: string | null; namedSpecifiers: string[];
    modulePath: string; quote: string;
  } | null {
    const t = line.trim();
    if (!t.startsWith('import ')) { return null; }
    // Side-effect: import 'module'
    const sideEffect = t.match(/^import\s+(['"])([^'"]+)\1\s*;?$/);
    if (sideEffect) {
      return { typeOnly: false, isNamespace: false, isSideEffect: true,
               defaultImport: null, namedSpecifiers: [],
               modulePath: sideEffect[2], quote: sideEffect[1] };
    }
    const typeOnly = /^import\s+type\s/.test(t);
    const body = typeOnly ? t.replace(/^import\s+type\s+/, 'import ') : t;
    // Namespace: import * as X from '...'
    const nsM = body.match(/^import\s+\*\s+as\s+(\w+)\s+from\s+(['"])([^'"]+)\2/);
    if (nsM) {
      return { typeOnly, isNamespace: true, isSideEffect: false,
               defaultImport: nsM[1], namedSpecifiers: [],
               modulePath: nsM[3], quote: nsM[2] };
    }
    const quoteM = body.match(/from\s+(['"])([^'"]+)\1/);
    if (!quoteM) { return null; }
    const quote = quoteM[1];
    const modulePath = quoteM[2];
    // Default + named: import Foo, { bar } from '...'
    const defaultNamed = body.match(/^import\s+(\w+)\s*,\s*\{([^}]*)\}\s+from/);
    if (defaultNamed) {
      return { typeOnly, isNamespace: false, isSideEffect: false,
               defaultImport: defaultNamed[1],
               namedSpecifiers: defaultNamed[2].split(',').map(s => s.trim()).filter(Boolean),
               modulePath, quote };
    }
    // Named only: import { foo, bar } from '...'
    const namedOnly = body.match(/^import\s+\{([^}]*)\}\s+from/);
    if (namedOnly) {
      return { typeOnly, isNamespace: false, isSideEffect: false,
               defaultImport: null,
               namedSpecifiers: namedOnly[1].split(',').map(s => s.trim()).filter(Boolean),
               modulePath, quote };
    }
    // Default only: import Foo from '...'
    const defaultOnly = body.match(/^import\s+(\w+)\s+from/);
    if (defaultOnly) {
      return { typeOnly, isNamespace: false, isSideEffect: false,
               defaultImport: defaultOnly[1], namedSpecifiers: [], modulePath, quote };
    }
    return null;
  }

  // Attempt to merge addLine's specifiers into resultLines[idx].
  // Returns the merged line on success, or null when the two imports are
  // incompatible and must stay as separate statements.
  function tryMerge(idx: number, addLine: string): string | null {
    const b = parseSingleLineImport(resultLines[idx]);
    const a = parseSingleLineImport(addLine);
    if (!b || !a) { return null; }
    if (b.isSideEffect  || a.isSideEffect)  { return null; } // side-effect — keep separate
    if (b.isNamespace   || a.isNamespace)   { return null; } // namespace   — keep separate
    if (b.typeOnly      !== a.typeOnly)     { return null; } // type vs value — keep separate
    if (b.defaultImport && a.defaultImport && b.defaultImport !== a.defaultImport) {
      log?.(`Import merge: conflicting default imports for '${b.modulePath}' — keeping both`);
      return null;
    }
    const mergedDefault = b.defaultImport ?? a.defaultImport;
    const seenSpec = new Set(b.namedSpecifiers);
    const merged   = [...b.namedSpecifiers, ...a.namedSpecifiers.filter(s => !seenSpec.has(s))];
    const prefix   = b.typeOnly ? 'import type ' : 'import ';
    const q        = b.quote;
    if (mergedDefault && merged.length > 0) {
      return `${prefix}${mergedDefault}, { ${merged.join(', ')} } from ${q}${b.modulePath}${q};`;
    } else if (mergedDefault) {
      return `${prefix}${mergedDefault} from ${q}${b.modulePath}${q};`;
    } else {
      return `${prefix}{ ${merged.join(', ')} } from ${q}${b.modulePath}${q};`;
    }
  }

  // Collect all module paths and mock paths from base imports
  for (const line of base.split('\n')) {
    const fromMatch = line.match(/from\s+['"]([^'"]+)['"]/);
    if (fromMatch) {
      const normalized = normalizeModulePath(fromMatch[1]);
      seenPaths.add(normalized);
      const bn = relativeBasename(fromMatch[1]);
      if (bn) { seenBasenames.add(bn); }
      // Track single-line, mergeable base imports so additions can merge into them.
      const parsed = parseSingleLineImport(line);
      if (parsed && !parsed.isNamespace && !parsed.isSideEffect) {
        baseImportAt.set(normalized, resultLines.length);
      }
    }
    const mockMatch = line.trim().match(/^(?:vi|jest)\.mock\s*\(\s*['"]([^'"]+)['"]/);
    if (mockMatch) { seenMockPaths.add(normalizeModulePath(mockMatch[1])); }
    resultLines.push(line);
  }

  if (base.trim()) { resultLines.push(''); } // blank line separator

  // Add only imports/mocks from additions that are new — or merge into existing
  let inMultiline = false;
  let pendingLines: string[] = [];

  for (const line of additions.split('\n')) {
    const t = line.trim();

    if (inMultiline) {
      pendingLines.push(line);
      const m = line.match(/from\s+['"]([^'"]+)['"]/);
      if (m) {
        inMultiline = false;
        const normalized = normalizeModulePath(m[1]);
        const bn         = relativeBasename(m[1]);
        if (seenPaths.has(normalized) || (bn !== null && seenBasenames.has(bn))) {
          // Multiline addition from a seen path: merging multiline is unsupported — skip
          log?.(`Import dedup: '${m[1]}' skipped (already seen as '${normalized}')`);
        } else {
          seenPaths.add(normalized);
          if (bn !== null) { seenBasenames.add(bn); }
          resultLines.push(...pendingLines);
        }
        pendingLines = [];
      }
      continue;
    }

    if (!t.startsWith('import ') && !t.startsWith('vi.mock(') && !t.startsWith('jest.mock(')) {
      if (t) { resultLines.push(line); }
      continue;
    }

    const fromMatch = line.match(/from\s+['"]([^'"]+)['"]/);
    if (fromMatch) {
      // Single-line import — deduplicate by normalized absolute path (primary)
      // and by basename of relative imports (secondary, catches ../x vs ../../x)
      const normalized = normalizeModulePath(fromMatch[1]);
      const bn         = relativeBasename(fromMatch[1]);
      if (seenPaths.has(normalized) || (bn !== null && seenBasenames.has(bn))) {
        // Path already seen — try to merge specifiers rather than drop the import
        const baseIdx = baseImportAt.get(normalized);
        if (baseIdx !== undefined) {
          const merged = tryMerge(baseIdx, line);
          if (merged !== null) {
            resultLines[baseIdx] = merged;
            log?.(`Import merge: merged '${fromMatch[1]}' into existing import`);
          } else {
            // Incompatible or conflicting — keep both (addition added as new line)
            resultLines.push(line);
          }
        } else {
          // Base import was multiline or namespace — cannot merge; skip addition
          log?.(`Import dedup: '${fromMatch[1]}' skipped (already seen as '${normalized}')`);
        }
      } else {
        seenPaths.add(normalized);
        if (bn !== null) { seenBasenames.add(bn); }
        resultLines.push(line);
        // Track this newly-added import so later additions can merge into it too
        const parsed = parseSingleLineImport(line);
        if (parsed && !parsed.isNamespace && !parsed.isSideEffect) {
          baseImportAt.set(normalized, resultLines.length - 1);
        }
      }
    } else if (t.startsWith('import ')) {
      // Start of multiline import
      inMultiline  = true;
      pendingLines = [line];
    } else {
      // vi/jest.mock call — filter local model/enum mocks; deduplicate the rest
      const mockPathMatch = t.match(/^(?:vi|jest)\.mock\s*\(\s*['"]([^'"]+)['"]/);
      if (mockPathMatch) {
        const mockPath = mockPathMatch[1];
        if (isLocalModelMockPath(mockPath)) { continue; } // drop — TS erases these at compile time
        const normalized = normalizeModulePath(mockPath);
        if (!seenMockPaths.has(normalized)) {
          seenMockPaths.add(normalized);
          resultLines.push(line);
        }
      } else {
        // Mock without an extractable path (e.g. computed path) — pass through
        resultLines.push(line);
      }
    }
  }

  return resultLines.join('\n').replace(/\n{3,}/g, '\n\n').trim();
}

// ─── Helper dedup by name (Case 3 migration only) ────────────────────────────
//
// Merge user helpers with AI helpers.
// If user already has a declaration with the same name, skip the AI version.

function mergeHelperBlocks(base: string, additions: string): string {
  const seenNames = new Set<string>();
  const resultLines: string[] = [];

  for (const line of base.split('\n')) {
    const m = line.trim().match(/^(?:export\s+)?(?:const|let|var|function|class)\s+(\w+)/);
    if (m) { seenNames.add(m[1]); }
    resultLines.push(line);
  }

  if (base.trim()) { resultLines.push(''); }

  let skipDepth = 0;
  let skipping  = false;

  for (const line of additions.split('\n')) {
    const t = line.trim();

    if (skipping) {
      for (const ch of line) {
        if (ch === '{') { skipDepth++; }
        if (ch === '}') { skipDepth--; }
      }
      if (skipDepth === 0) { skipping = false; }
      continue;
    }

    const m = t.match(/^(?:export\s+)?(?:const|let|var|function|class)\s+(\w+)/);
    if (m && seenNames.has(m[1])) {
      skipping = true;
      skipDepth = 0;
      for (const ch of line) {
        if (ch === '{') { skipDepth++; }
        if (ch === '}') { skipDepth--; }
      }
      if (skipDepth === 0) { skipping = false; }
      continue;
    }

    if (m) { seenNames.add(m[1]); }
    resultLines.push(line);
  }

  return resultLines.join('\n').replace(/\n{3,}/g, '\n\n').trim();
}

// ─── Extract existing content from legacy file (Case 3) ───────────────────────

interface LegacyContent { imports: string; helpers: string; tests: string; }

function extractLegacyContent(existing: string): LegacyContent {
  // Strip all SS markers from any previous format
  let content = existing
    .replace(/^\/\/ @auto-generated by SilentSpec.*\n(\/\/ Source:.*\n)?(\/\/ Functions covered:.*\n)?/, '')
    .replace(/\/\/ <SS-USER-IMPORTS-START>[\s\S]*?\/\/ <SS-USER-IMPORTS-END>\n?/g, '')
    .replace(/\/\/ <SS-IMPORTS-START>[\s\S]*?\/\/ <SS-IMPORTS-END>\n?/g, '')
    .replace(/\/\/ <SS-USER-HELPERS-START>[\s\S]*?\/\/ <SS-USER-HELPERS-END>\n?/g, '')
    .replace(/\/\/ <SS-HELPERS-START>[\s\S]*?\/\/ <SS-HELPERS-END>\n?/g, '')
    .replace(/\/\/ <SS-USER-TESTS>[\s\S]*?\/\/ <\/SS-USER-TESTS>\n?/g, '')
    .replace(/\/\/ <SS-GENERATED-START[^\n]*\n[\s\S]*?\/\/ <SS-GENERATED-END>\n?/g, '');

  const lines = content.split('\n');
  const importLines: string[] = [];
  const remainingLines: string[] = [];
  let mockParenDepth   = 0;
  let importBraceDepth = 0;

  // Pass 1: separate imports/mocks from everything else
  for (const line of lines) {
    const t = line.trim();

    if (mockParenDepth > 0) {
      importLines.push(line);
      for (const ch of line) {
        if (ch === '(') { mockParenDepth++; }
        if (ch === ')') { mockParenDepth--; }
      }
      continue;
    }

    if (importBraceDepth > 0) {
      importLines.push(line);
      for (const ch of line) {
        if (ch === '{') { importBraceDepth++; }
        if (ch === '}') { importBraceDepth--; }
      }
      continue;
    }

    if (t.startsWith('import ')) {
      importLines.push(line);
      for (const ch of line) {
        if (ch === '{') { importBraceDepth++; }
        if (ch === '}') { importBraceDepth--; }
      }
      continue;
    }

    if (t.startsWith('vi.mock(') || t.startsWith('jest.mock(')) {
      importLines.push(line);
      for (const ch of line) {
        if (ch === '(') { mockParenDepth++; }
        if (ch === ')') { mockParenDepth--; }
      }
      continue;
    }

    remainingLines.push(line);
  }

  // Pass 2: separate helper declarations from test blocks
  // NOTE: brace depth tracking is heuristic — may miscount for braces inside
  // template literals or strings, but handles the vast majority of real files.
  const helperLines: string[] = [];
  const testLines: string[]   = [];
  let inTestBlock = false;
  let testDepth   = 0;

  for (const line of remainingLines) {
    const t = line.trim();

    if (!inTestBlock) {
      // Regex catches describe/test/it plus variants like describe.only, test.each etc.
      const isTestStart = /^(describe|test|it)[\s.(]/.test(t);

      if (isTestStart) {
        inTestBlock = true;
        testLines.push(line);
        for (const ch of line) {
          if (ch === '{') { testDepth++; }
          if (ch === '}') { testDepth--; }
        }
      } else if (t.length > 0) {
        helperLines.push(line);
      }
    } else {
      testLines.push(line);
      for (const ch of line) {
        if (ch === '{') { testDepth++; }
        if (ch === '}') { testDepth--; }
      }
      if (testDepth === 0) {
        inTestBlock = false;
        testDepth   = 0;
        testLines.push('');
      }
    }
  }

  return {
    imports: importLines.join('\n').trim(),
    helpers: helperLines.join('\n').trim(),
    tests:   testLines.join('\n').trim(),
  };
}

// ─── Spec path resolution ─────────────────────────────────────────────────────

function isTestDirPath(dir: string): boolean {
  return TEST_DIRS.includes(path.basename(dir));
}

function countConventions(files: string[], dir: string): { spec: number; test: number } {
  return {
    spec: files.filter(f => /\.spec\.[tj]sx?$/.test(f)).length,
    test: files.filter(f =>
      /\.test\.[tj]sx?$/.test(f) ||
      (isTestDirPath(dir) && /^tests?\.[tj]sx?$/.test(f))
    ).length,
  };
}

function resolveConvention(
  counts: { spec: number; test: number },
  location: string,
  emit: (msg: string) => void
): '.spec.ts' | '.test.ts' | null {
  if (counts.test === 0 && counts.spec === 0) { return null; }
  if (counts.test > counts.spec) {
    emit(`Naming convention: .test.ts (${counts.test} vs ${counts.spec} .spec files in ${location})`);
    return '.test.ts';
  }
  emit(`Naming convention: .spec.ts (${counts.spec} vs ${counts.test} .test files in ${location})`);
  return '.spec.ts';
}

async function detectNamingConvention(dir: string, log?: (msg: string) => void): Promise<'.spec.ts' | '.test.ts'> {
  const emit = log ?? (() => {});

  for (const testDir of TEST_DIRS) {
    const testDirPath = path.join(dir, testDir);
    if (fs.existsSync(testDirPath) && fs.lstatSync(testDirPath).isDirectory()) {
      try {
        const files = fs.readdirSync(testDirPath);
        const result = resolveConvention(countConventions(files, testDirPath), testDirPath, emit);
        if (result) { return result; }
      } catch { /* skip */ }
    }
  }

  try {
    const files = fs.readdirSync(dir);
    const result = resolveConvention(countConventions(files, dir), dir, emit);
    if (result) { return result; }
  } catch { /* skip */ }

  const workspaceFolders = vscode.workspace.workspaceFolders;
  const workspaceRoot    = workspaceFolders?.[0]?.uri.fsPath;
  let current = path.dirname(dir);
  while (current !== dir && workspaceRoot && current.startsWith(workspaceRoot)) {
    try {
      const files = fs.readdirSync(current);
      const result = resolveConvention(countConventions(files, current), current, emit);
      if (result) { return result; }
    } catch { /* skip */ }
    dir     = current;
    current = path.dirname(current);
  }

  const [testFiles, specFiles] = await Promise.all([
    vscode.workspace.findFiles('**/*.test.{ts,tsx,js,jsx}', '**/node_modules/**', 10),
    vscode.workspace.findFiles('**/*.spec.{ts,tsx,js,jsx}', '**/node_modules/**', 10),
  ]);
  const workspaceResult = resolveConvention(
    { test: testFiles.length, spec: specFiles.length },
    'workspace',
    emit
  );
  if (workspaceResult) { return workspaceResult; }
  emit('Naming convention: .spec.ts (default — no existing test files found)');
  return '.spec.ts';
}

function findAncestorTestDirs(sourceDir: string, workspaceRoot: string): string[] {
  const results: string[] = [];
  const seen = new Set<string>();
  let current = sourceDir;
  const boundary = sourceDir.startsWith(workspaceRoot)
    ? workspaceRoot
    : path.parse(sourceDir).root;

  while (current.startsWith(boundary)) {
    for (const testDir of TEST_DIRS) {
      const candidate = path.join(current, testDir);
      if (seen.has(candidate)) { continue; }
      if (fs.existsSync(candidate) && fs.lstatSync(candidate).isDirectory()) {
        seen.add(candidate);
        results.push(candidate);
      }
    }
    if (current === boundary) { break; }
    const parent = path.dirname(current);
    if (parent === current) { break; }
    current = parent;
  }

  return results;
}

function isAdjacentTestDir(testDirPath: string, sourceDir: string): boolean {
  return path.dirname(testDirPath) === sourceDir;
}

function deriveSisterPath(unmanagedPath: string): string {
  return unmanagedPath.replace(
    /\.(spec|test)(\.[tj]sx?)$/,
    '.silentspec.$1$2'
  );
}

function buildSpecCandidates(base: string, allExts: string[]): string[] {
  return allExts.map(e => `${base}${e}`);
}

function buildSisterCandidates(base: string, allExts: string[]): string[] {
  return allExts.map(e =>
    `${base}${e.replace(/\.(spec|test)(\.[tj]sx?)$/, '.silentspec.$1$2')}`
  );
}

function readManagedState(candidate: string): 'managed' | 'unmanaged' | 'unreadable' {
  try {
    const content = fs.readFileSync(candidate, 'utf8');
    return isUnmanagedContent(content) ? 'unmanaged' : 'managed';
  } catch {
    return 'unreadable';
  }
}

export async function resolveSpecPathWithInfo(sourcePath: string, log?: (msg: string) => void): Promise<SpecPathResolution> {
  const emit = log ?? (() => {});
  const ext  = path.extname(sourcePath);
  const base = path.basename(sourcePath, ext);
  const dir  = path.dirname(sourcePath);

  const convention = await detectNamingConvention(dir, log);

  const preferredExt = (() => {
    if (ext === '.tsx') { return convention === '.test.ts' ? '.test.tsx' : '.spec.tsx'; }
    if (ext === '.jsx') { return convention === '.test.ts' ? '.test.jsx' : '.spec.jsx'; }
    if (ext === '.js')  { return convention === '.test.ts' ? '.test.js'  : '.spec.js';  }
    return convention;
  })();
  const specName = `${base}${preferredExt}`;

  const allVariants = [
    '.spec.ts', '.test.ts', '.spec.tsx', '.test.tsx',
    '.spec.js', '.test.js', '.spec.jsx', '.test.jsx',
  ];
  const primaryExts  = allVariants.filter(e => e.endsWith(ext));
  const fallbackExts = allVariants.filter(e => !e.endsWith(ext));
  const allExts      = [...primaryExts, ...fallbackExts];
  const normalCandidates = buildSpecCandidates(base, allExts);
  const sisterCandidates = buildSisterCandidates(base, allExts);
  const workspaceFolder = vscode.workspace.getWorkspaceFolder(vscode.Uri.file(sourcePath));
  const workspaceRoot = workspaceFolder?.uri.fsPath ?? dir;
  const ancestorTestDirs = findAncestorTestDirs(dir, workspaceRoot);

  const findManagedSister = (searchDir: string, reason: SpecPathResolution['reason']): SpecPathResolution | null => {
    for (const candidateName of sisterCandidates) {
      const candidate = path.join(searchDir, candidateName);
      if (!fs.existsSync(candidate)) { continue; }
      if (readManagedState(candidate) === 'managed') {
        emit(`Spec path resolved (${reason}): ${candidate}`);
        return { specPath: candidate, reason };
      }
    }
    return null;
  };

  const findManagedOrUnmanagedNormal = (searchDir: string, managedReason: SpecPathResolution['reason']): SpecPathResolution | null => {
    for (const candidateName of normalCandidates) {
      const candidate = path.join(searchDir, candidateName);
      if (!fs.existsSync(candidate)) { continue; }
      const state = readManagedState(candidate);
      if (state === 'managed') {
        emit(`Spec path resolved (${managedReason}): ${candidate}`);
        return { specPath: candidate, reason: managedReason };
      }
      if (state === 'unmanaged') {
        const sisterPath = deriveSisterPath(candidate);
        emit(`Spec path resolved (new sister for unmanaged spec): ${sisterPath}`);
        return { specPath: sisterPath, companionPath: candidate, reason: 'new-sister-for-unmanaged' };
      }
    }
    return null;
  };

  // Pass 1 — existing managed file in test folders from closest to furthest.
  for (const testDirPath of ancestorTestDirs) {
    const sister = findManagedSister(testDirPath, 'existing-managed-sister');
    if (sister) { return sister; }
    const normal = findManagedOrUnmanagedNormal(
      testDirPath,
      isAdjacentTestDir(testDirPath, dir) ? 'existing-managed' : 'existing-managed-ancestor'
    );
    if (normal) { return normal; }
  }

  // Pass 2 — existing file in same directory as source
  const besideSister = findManagedSister(dir, 'existing-managed-sister');
  if (besideSister) { return besideSister; }
  const besideNormal = findManagedOrUnmanagedNormal(dir, 'existing-managed');
  if (besideNormal) { return besideNormal; }

  // Pass 3 — existing spec in root-level test dirs (lookup only — never creates new files here).
  // Checks both mirrored paths (e.g. __tests__/src/utils/foo.spec.ts) and flat paths
  // (e.g. __tests__/foo.spec.ts). Flat paths require basename collision check because
  // multiple source files can share the same basename.
  let collisionDetected = false;
  if (workspaceRoot && workspaceRoot !== dir) {
    for (const testDir of TEST_DIRS) {
      const rootTestDir = path.join(workspaceRoot, testDir);
      if (!fs.existsSync(rootTestDir) || !fs.lstatSync(rootTestDir).isDirectory()) { continue; }

      // Mirrored path — directory structure disambiguates, no collision possible
      const relativePath = path.relative(workspaceRoot, dir);
      for (const candidateName of [...sisterCandidates, ...normalCandidates]) {
        const mirroredCandidate = path.join(rootTestDir, relativePath, candidateName);
        if (fs.existsSync(mirroredCandidate)) {
          const state = readManagedState(mirroredCandidate);
          if (state === 'managed') {
            const reason = candidateName.includes('.silentspec.') ? 'existing-managed-sister' : 'existing-managed';
            emit(`Spec path resolved (pass 3 — existing in root test dir, mirrored): ${mirroredCandidate}`);
            return { specPath: mirroredCandidate, reason };
          }
          if (state === 'unmanaged') {
            const sisterPath = deriveSisterPath(mirroredCandidate);
            emit(`Spec path resolved (pass 3 — new sister for unmanaged mirrored spec): ${sisterPath}`);
            return { specPath: sisterPath, companionPath: mirroredCandidate, reason: 'new-sister-for-unmanaged' };
          }
        }
      }

      // Flat path — basename collision possible, verify the spec belongs to this source.
      // New specs store a relative path (e.g. "src/api/utils.ts") in the Source header.
      // Legacy specs store only the basename (e.g. "utils.ts"). Accept a basename-only
      // match only when the source file is directly in the workspace root, since that is
      // the one case where relative path === basename — no ambiguity.
      const relSource = workspaceRoot
        ? path.relative(workspaceRoot, sourcePath)
        : path.basename(sourcePath);
      const basenameOnly = path.basename(sourcePath);
      const sourceIsAtWorkspaceRoot =
        !!workspaceRoot && path.dirname(sourcePath) === workspaceRoot;
      for (const candidateName of [...sisterCandidates, ...normalCandidates]) {
        const flatCandidate = path.join(rootTestDir, candidateName);
        if (!fs.existsSync(flatCandidate)) { continue; }
        try {
          const content = fs.readFileSync(flatCandidate, 'utf8');
          if (isUnmanagedContent(content)) {
            if (!sourceIsAtWorkspaceRoot) {
              emit('Spec placement: unmanaged root test-dir basename collision risk — placing beside source');
              collisionDetected = true;
              break;
            }
            const sisterPath = deriveSisterPath(flatCandidate);
            emit(`Spec path resolved (pass 3 — new sister for unmanaged root spec): ${sisterPath}`);
            return { specPath: sisterPath, companionPath: flatCandidate, reason: 'new-sister-for-unmanaged' };
          }
          const ownsSpec =
            content.includes(`// Source: ${relSource}`) ||
            (sourceIsAtWorkspaceRoot && content.includes(`// Source: ${basenameOnly}`));
          if (ownsSpec) {
            emit(`Spec path resolved (pass 3 — existing in root test dir): ${flatCandidate}`);
            const reason = candidateName.includes('.silentspec.') ? 'existing-managed-sister' : 'existing-managed';
            return { specPath: flatCandidate, reason };
          }
        } catch { /* can't read → can't prove ownership */ }
        // Cannot prove this spec belongs to the current source file — collision
        emit('Spec placement: basename collision detected — placing beside source');
        collisionDetected = true;
        break;
      }
      if (collisionDetected) { break; }
    }
  }

  // Pass 4 — new file in adjacent test dir, only if that directory already has spec files
  // (established pattern). Skipped when a basename collision was detected — fall straight
  // through to beside-source placement for safety.
  if (!collisionDetected) {
    for (const testDir of TEST_DIRS) {
      const adjacentTestDir = path.join(dir, testDir);
      if (!fs.existsSync(adjacentTestDir) || !fs.lstatSync(adjacentTestDir).isDirectory()) { continue; }
      try {
        const files = fs.readdirSync(adjacentTestDir);
        const counts = countConventions(files, adjacentTestDir);
        if (counts.test > 0 || counts.spec > 0) {
          const resolved = path.join(adjacentTestDir, specName);
          emit(`Spec path resolved (pass 4 — new file in established test dir): ${resolved}`);
          return { specPath: resolved, reason: 'new-established-dir' };
        }
      } catch { /* skip unreadable directory */ }
    }
  }

  // Pass 5 — fallback: new file beside source
  const fallback = path.join(dir, specName);
  emit(`Spec path resolved (pass 5 — fallback, same dir as source): ${fallback}`);
  return { specPath: fallback, reason: 'new-fallback' };
}

export async function resolveSpecPath(sourcePath: string, log?: (msg: string) => void): Promise<string> {
  return (await resolveSpecPathWithInfo(sourcePath, log)).specPath;
}

// ─── Low-level writer ─────────────────────────────────────────────────────────

async function writeSpecFileToPath(
  specPath: string,
  finalContent: string,
  log: (msg: string) => void,
  targetedRange?: { startIdx: number; endIdx: number; newBlock: string },
  isNew: boolean = false
): Promise<void> {
  const specUri = vscode.Uri.file(specPath);
  try {
    const contentToWrite = targetedRange
      ? finalContent.slice(0, targetedRange.startIdx) +
        targetedRange.newBlock +
        finalContent.slice(targetedRange.endIdx)
      : finalContent;

    await vscode.workspace.fs.writeFile(specUri, Buffer.from(contentToWrite, 'utf8'));

    if (targetedRange) {
      log(`Updated: ${path.basename(specPath)} (targeted splice)`);
    } else {
      if (isNew) {
        log(`Created: ${path.basename(specPath)}`);
      } else {
        log(`Updated: ${path.basename(specPath)}`);
      }
    }
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    if (msg.includes('EACCES') || msg.includes('permission')) {
      void vscode.window.showErrorMessage('SilentSpec: Cannot write spec file — check folder permissions.');
    }
    log(`Error: file writer failed for ${path.basename(specPath)} — ${msg}`);
  }
}

// ─── Main entry point ─────────────────────────────────────────────────────────
//
// Case 1 — New file: build full 4-block structure from scratch.
//
// Case 2 — Existing file with full structure (steady state):
//   Replace SS-IMPORTS, SS-HELPERS, SS-GENERATED every run.
//   SS-USER-TESTS is never touched.
//
// Case 3 — Existing file without structure (one-time migration):
//   Extract user's imports → merge with AI imports (dedup by module path) → SS-IMPORTS
//   Extract user's helpers → merge with AI helpers (dedup by name) → SS-HELPERS
//   Extract user's test blocks → SS-USER-TESTS (never touched again)
//   AI generated tests → SS-GENERATED

export async function writeSpecFile(
  sourcePath: string,
  aiOutput: string,
  log: (msg: string) => void,
  marker: SSMarker,
  exportedFunctions?: string[],
  mode: 'replace' | 'append' = 'replace'
): Promise<boolean> {
  const resolution = await resolveSpecPathWithInfo(sourcePath, log);
  const specPath = resolution.specPath;
  const { importsBlock: rawImportsBlock, helpersBlock: rawHelpersBlock, testsBlock: rawGeneratedBlock } = splitAIOutput(aiOutput, marker);
  // Layer 1: remove echoed zone-marker lines and header lines from the import/helper buckets.
  // If the LLM echoes the full file zone structure, those marker lines land here and would
  // produce duplicate markers when replaceSystemZones inserts the block between zone tags.
  const importsBlock   = stripEchoedLinesFromBlock(rawImportsBlock);
  const helpersBlock   = stripEchoedLinesFromBlock(rawHelpersBlock);
  // Layer 2: remove any echoed SS-USER-TESTS block from the tests bucket.
  // If the LLM copies user test content into its output it lands in generatedBlock and
  // would produce duplicate describe blocks in SS-GENERATED.
  const generatedBlock = stripEchoedUserTestsSection(rawGeneratedBlock);

  const markerSummary =
    `covered: [${marker.covered.join(', ')}]` +
    (marker.pending.length > 0 ? ` pending: [${marker.pending.join(', ')}]` : '');

  // ── Case 1: Brand new file ─────────────────────────────────────────────────
  if (!fs.existsSync(specPath)) {
    const specUri = vscode.Uri.file(specPath);
    const edit    = new vscode.WorkspaceEdit();
    const content = buildFullFile(
      importsBlock, helpersBlock, SS_USER_PLACEHOLDER, generatedBlock,
      sourcePath,
      marker.covered,   // only functions actually covered in this generation
      resolution.companionPath
    );
    // Layer 3: validate assembled marker counts before creating the file.
    const newFileMarkerError = validateAssembledMarkerCounts(content);
    if (newFileMarkerError) {
      log(`Warning: assembled spec marker error (${newFileMarkerError}) — aborting write`);
      return false;
    }
    edit.createFile(specUri, { overwrite: false, ignoreIfExists: false });
    if (!await vscode.workspace.applyEdit(edit)) {
      throw new Error(`applyEdit failed to create spec file: ${specPath}`);
    }
    await writeSpecFileToPath(specPath, content, log, undefined, true);
    log(`New spec created — ${markerSummary}`);
    return true;
  }

  // Read existing file
  let existing: string;
  try {
    existing = fs.readFileSync(specPath, 'utf8');
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    log(`Warning: could not read existing spec (${msg}) — skipping`);
    return false;
  }

  if (existing.includes('<<<<<<<')) {
    log('Warning: Git conflict markers detected — skipping write');
    void vscode.window.showWarningMessage('SilentSpec: Resolve Git conflicts before regenerating.');
    return false;
  }

  // Guard: unmanaged spec file — has neither SilentSpec header nor any SS marker.
  // isUnmanagedContent is the shared detection logic; this call is the final safety net.
  if (isUnmanagedContent(existing)) {
    log('Spec file: not managed by SilentSpec — skipping');
    return false;
  }

  // Guard: detect broken SS marker structure before any write or migration
  const hasStart = existing.includes('// <SS-GENERATED-START');
  const hasEnd = existing.includes('// <SS-GENERATED-END>');
  const hasUserBlock = existing.includes('// <SS-USER-TESTS>');

  if (hasStart || hasEnd || hasUserBlock) {
    // File has partial SS structure — validate before proceeding
    const startCount = (existing.match(/\/\/ <SS-GENERATED-START/g) || []).length;
    const endCount = (existing.match(/\/\/ <SS-GENERATED-END>/g) || []).length;
    const startIdx = existing.indexOf('// <SS-GENERATED-START');
    const endIdx = existing.indexOf('// <SS-GENERATED-END>');

    if (startCount > 1) {
      log('Spec file: duplicate SS-GENERATED-START marker');
      return false;
    }
    if (hasStart && !hasEnd) {
      log('Spec file: missing SS-GENERATED-END marker');
      return false;
    }
    if (!hasStart && hasEnd) {
      log('Spec file: missing SS-GENERATED-START marker');
      return false;
    }
    if (hasStart && hasEnd && endIdx < startIdx) {
      log('Spec file: markers out of order');
      return false;
    }
  }

  // Guard: SS-GENERATED intact but other zones missing/broken → skip, never migrate
  if (hasStart && hasEnd) {
    const startIdx = existing.indexOf('// <SS-GENERATED-START');
    const endIdx = existing.indexOf('// <SS-GENERATED-END>');
    if (startIdx < endIdx && !hasFullStructure(existing)) {
      log('Spec file: incomplete zone structure — skipping write');
      return false;
    }
  }

  // Guard: verify ALL zone markers appear in correct order
  // Required order: SS-IMPORTS-START → SS-IMPORTS-END → SS-HELPERS-START → SS-HELPERS-END
  //                 → SS-USER-TESTS → /SS-USER-TESTS → SS-GENERATED-START → SS-GENERATED-END
  // Skip this validation entirely when no zone markers are present — a header-only file
  // has no markers yet and is a valid Case 3 migration target.
  const hasAnyZoneMarker =
    existing.includes('// <SS-IMPORTS-START>') ||
    existing.includes('// <SS-HELPERS-START>') ||
    hasUserBlock ||
    hasStart;

  const posImportsStart  = existing.indexOf('// <SS-IMPORTS-START>');
  const posImportsEnd    = existing.indexOf('// <SS-IMPORTS-END>');
  const posHelpersStart  = existing.indexOf('// <SS-HELPERS-START>');
  const posHelpersEnd    = existing.indexOf('// <SS-HELPERS-END>');
  const posUserStart     = existing.indexOf('// <SS-USER-TESTS>');
  const posUserEnd       = existing.indexOf('// </SS-USER-TESTS>');
  const posGenStart      = existing.indexOf('// <SS-GENERATED-START');
  const posGenEnd        = existing.indexOf('// <SS-GENERATED-END>');

  const zoneOrderValid =
    posImportsStart  < posImportsEnd   &&
    posImportsEnd    < posHelpersStart &&
    posHelpersStart  < posHelpersEnd   &&
    posHelpersEnd    < posUserStart    &&
    posUserStart     < posUserEnd      &&
    posUserEnd       < posGenStart     &&
    posGenStart      < posGenEnd;

  if (hasAnyZoneMarker && !zoneOrderValid) {
    const zoneOrderReason =
      posImportsStart  >= posImportsEnd   ? 'SS-IMPORTS-START must precede SS-IMPORTS-END' :
      posImportsEnd    >= posHelpersStart ? 'SS-IMPORTS-END must precede SS-HELPERS-START' :
      posHelpersStart  >= posHelpersEnd   ? 'SS-HELPERS-START must precede SS-HELPERS-END' :
      posHelpersEnd    >= posUserStart    ? 'SS-HELPERS-END must precede SS-USER-TESTS' :
      posUserStart     >= posUserEnd      ? 'SS-USER-TESTS must precede /SS-USER-TESTS' :
      posUserEnd       >= posGenStart     ? '/SS-USER-TESTS must precede SS-GENERATED-START' :
      'SS-GENERATED-START must precede SS-GENERATED-END';
    log('Spec file: zone order invalid — skipping write');
    log(`Context: ${zoneOrderReason}`);
    return false;
  }

  // ── Case 2: Existing file with full 4-block structure ─────────────────────
  if (hasFullStructure(existing)) {
    const validationError = validateSSStructure(existing);
    if (validationError) {
      log(`Warning: SS structure invalid — ${validationError} — skipping write`);
      return false;
    }

    // Replace system zones — SS-USER-TESTS is never touched.
    // In append mode, only SS-GENERATED is updated — SS-IMPORTS and SS-HELPERS are preserved.
    // null return means duplicate markers detected — abort entire write.
    let withSystemZones = mode === 'append'
      ? injectCoveredFunctionsIntoImports(existing, sourcePath, specPath, marker.covered, log)
      : replaceSystemZones(existing, importsBlock, helpersBlock, log);
    if (withSystemZones === null) { return false; }
    withSystemZones = updateFunctionsCoveredHeader(withSystemZones, marker.covered, log);

    const { startIdx, endIdx } = readMarker(withSystemZones);
    if (startIdx === -1 || endIdx === -1 || startIdx >= endIdx) {
      log('Warning: readMarker returned invalid range — writing system zones only');
      await writeSpecFileToPath(specPath, withSystemZones, log);
      return true;
    }

    const newTestBody = generatedBlock
      .replace(/^\/\/ <SS-GENERATED-START[^\n]*\n/, '')
      .replace(/\n\/\/ <SS-GENERATED-END>$/, '')
      .trim();

    const testBody = (() => {
      if (mode === 'append') {
        const { innerContent: existingGenerated } = readMarker(withSystemZones);
        return existingGenerated.trim()
          ? `${existingGenerated.trim()}\n\n${newTestBody}`
          : newTestBody;
      }
      return newTestBody;
    })();

    const newBlock = [buildMarkerLine(marker), testBody, SS_END].join('\n');

    log(`SS-GENERATED updated — ${markerSummary}`);

    if (withSystemZones !== existing) {
      // System zones changed — full write
      const finalContent =
        withSystemZones.slice(0, startIdx) +
        newBlock +
        withSystemZones.slice(endIdx);
      // Layer 3: validate assembled marker counts before write.
      const fullWriteMarkerError = validateAssembledMarkerCounts(finalContent);
      if (fullWriteMarkerError) {
        log(`Warning: assembled spec marker error (${fullWriteMarkerError}) — aborting write`);
        return false;
      }
      await writeSpecFileToPath(specPath, finalContent, log);
    } else {
      // Only SS-GENERATED changed — surgical splice.
      // Assemble the full content for validation only; write uses the targeted splice.
      const spliceAssembled = withSystemZones.slice(0, startIdx) + newBlock + withSystemZones.slice(endIdx);
      const spliceMarkerError = validateAssembledMarkerCounts(spliceAssembled);
      if (spliceMarkerError) {
        log(`Warning: assembled spec marker error (${spliceMarkerError}) — aborting write`);
        return false;
      }
      await writeSpecFileToPath(specPath, withSystemZones, log, { startIdx, endIdx, newBlock });
    }
    return true;
  }

  // ── Case 3: One-time migration ─────────────────────────────────────────────
  // Extract user's existing content, merge with AI output, build full structure.
  // After this run the file has full structure — all subsequent saves hit Case 2.
  log('Notice: migrating existing file into SilentSpec zone structure');
  const legacy = extractLegacyContent(existing);

  // Merge imports: user's first (base), AI adds only new module paths
  const mergedImports = mergeImportBlocks(legacy.imports, importsBlock, path.dirname(specPath), log);

  // Merge helpers: user's first (base), AI adds only new named declarations
  const mergedHelpers = mergeHelperBlocks(legacy.helpers, helpersBlock);

  // User's test blocks go into SS-USER-TESTS — never touched again
  const userTests = legacy.tests || SS_USER_PLACEHOLDER;

  const finalContent = buildFullFile(
    mergedImports,
    mergedHelpers,
    userTests,
    generatedBlock,
    sourcePath,
    marker.covered,   // only functions actually covered in this generation
    resolution.companionPath
  );

  // Layer 3: validate assembled marker counts before write.
  const migrationMarkerError = validateAssembledMarkerCounts(finalContent);
  if (migrationMarkerError) {
    log(`Warning: assembled spec marker error (${migrationMarkerError}) — aborting write`);
    return false;
  }
  await writeSpecFileToPath(specPath, finalContent, log);
  log(`Migration complete — existing content preserved — ${markerSummary}`);
  return true;
}

// ─── Gap batch append helpers ─────────────────────────────────────────────────

interface SourceImportParts {
  line: string;
  trimmed: string;
  rawModPath: string;
  quote: string;
  existingDefault: string | null;
  existingNamed: string[];
  indent: string;
}

function parseSourceImportLine(line: string): SourceImportParts | null {
  const t = line.trim();
  if (!t.startsWith('import ')) { return null; }

  const fromM = t.match(/from\s+(['"])([^'"]+)\1/);
  if (!fromM) { return null; }

  if (/^import\s+type\s/.test(t) ||
      /^import\s+\*\s+as/.test(t) ||
      /^import\s+['"]/.test(t)) {
    return null;
  }

  let existingDefault: string | null = null;
  let existingNamed: string[]        = [];

  const defaultNamedM = t.match(/^import\s+(\w+)\s*,\s*\{([^}]*)\}\s+from/);
  if (defaultNamedM) {
    existingDefault = defaultNamedM[1];
    existingNamed   = defaultNamedM[2].split(',').map(s => s.trim()).filter(Boolean);
  } else {
    const namedOnlyM = t.match(/^import\s+\{([^}]*)\}\s+from/);
    if (namedOnlyM) {
      existingNamed = namedOnlyM[1].split(',').map(s => s.trim()).filter(Boolean);
    } else {
      const defaultOnlyM = t.match(/^import\s+(\w+)\s+from/);
      if (defaultOnlyM) { existingDefault = defaultOnlyM[1]; }
    }
  }

  return {
    line,
    trimmed: t,
    rawModPath: fromM[2],
    quote: fromM[1],
    existingDefault,
    existingNamed,
    indent: line.match(/^(\s*)/)?.[1] ?? '',
  };
}

function buildSourceImportLine(parts: SourceImportParts, coveredFunctions: string[]): string | null {
  const coveredSet = new Set(coveredFunctions);
  const defaultImport = parts.existingDefault && coveredSet.has(parts.existingDefault)
    ? parts.existingDefault
    : null;
  const namedImports = coveredFunctions.filter(fn => fn !== defaultImport);

  if (!defaultImport && namedImports.length === 0) { return null; }

  if (defaultImport && namedImports.length > 0) {
    return `${parts.indent}import ${defaultImport}, { ${namedImports.join(', ')} } from ${parts.quote}${parts.rawModPath}${parts.quote};`;
  }
  if (defaultImport) {
    return `${parts.indent}import ${defaultImport} from ${parts.quote}${parts.rawModPath}${parts.quote};`;
  }
  return `${parts.indent}import { ${namedImports.join(', ')} } from ${parts.quote}${parts.rawModPath}${parts.quote};`;
}

function resolveSourceImportNoExt(specDir: string, rawModPath: string): string {
  return path.resolve(specDir, rawModPath).replace(/\.[tj]sx?$/, '');
}

// Update the source-module import line inside SS-IMPORTS to include any
// function names from coveredFunctions that are not already imported.
// Returns the updated specContent string, or the original if no change is needed.
function injectCoveredFunctionsIntoImports(
  specContent: string,
  sourcePath: string,
  specPath: string,
  coveredFunctions: string[],
  log: (msg: string) => void
): string {
  if (coveredFunctions.length === 0) { return specContent; }

  const specDir      = path.dirname(specPath);
  // Normalize source path: strip extension so we can compare against import specifiers
  // which conventionally omit it (e.g. from '../converter').
  const sourceNoExt  = path.join(
    path.dirname(sourcePath),
    path.basename(sourcePath, path.extname(sourcePath))
  );

  const importsStart = specContent.indexOf(SS_IMPORTS_START);
  const importsEnd   = specContent.indexOf(SS_IMPORTS_END);
  if (importsStart === -1 || importsEnd === -1 || importsStart >= importsEnd) {
    log('Gap append: SS-IMPORTS zone not found — import update skipped');
    return specContent;
  }

  // Work on just the lines between the two zone markers
  const zoneContent  = specContent.slice(importsStart + SS_IMPORTS_START.length, importsEnd);
  const importLines  = zoneContent.split('\n');

  let patchedLineIdx = -1;
  let patchedLine    = '';

  for (let i = 0; i < importLines.length; i++) {
    const line = importLines[i];
    const parts = parseSourceImportLine(line);
    if (!parts) { continue; }

    // Resolve the import specifier to an absolute path without extension
    const resolvedNoExt = resolveSourceImportNoExt(specDir, parts.rawModPath);
    if (resolvedNoExt !== sourceNoExt) { continue; }

    // Merge: add only function names not already imported
    const existingSet = new Set(parts.existingNamed);
    const newNames    = coveredFunctions.filter(fn => !existingSet.has(fn));
    if (newNames.length === 0) { return specContent; } // nothing to add

    const mergedNamed = [...parts.existingNamed, ...newNames];
    const mergedLine = buildSourceImportLine({ ...parts, existingNamed: mergedNamed }, [
      ...(parts.existingDefault ? [parts.existingDefault] : []),
      ...mergedNamed,
    ]);
    if (!mergedLine) { return specContent; }

    patchedLineIdx = i;
    patchedLine    = mergedLine;
    break;
  }

  if (patchedLineIdx === -1) {
    log('Gap append: source-module import not found in SS-IMPORTS — import update skipped');
    return specContent;
  }

  importLines[patchedLineIdx] = patchedLine;
  return (
    specContent.slice(0, importsStart + SS_IMPORTS_START.length) +
    importLines.join('\n') +
    specContent.slice(importsEnd)
  );
}

function syncCoveredFunctionsImport(
  specContent: string,
  sourcePath: string,
  specPath: string,
  coveredFunctions: string[],
  log: (msg: string) => void
): string {
  const specDir = path.dirname(specPath);
  const sourceNoExt = path.join(
    path.dirname(sourcePath),
    path.basename(sourcePath, path.extname(sourcePath))
  );

  const importsStart = specContent.indexOf(SS_IMPORTS_START);
  const importsEnd   = specContent.indexOf(SS_IMPORTS_END);
  if (importsStart === -1 || importsEnd === -1 || importsStart >= importsEnd) {
    log('Spec metadata repair: SS-IMPORTS zone not found — import prune skipped');
    return specContent;
  }

  const zoneContent = specContent.slice(importsStart + SS_IMPORTS_START.length, importsEnd);
  const importLines = zoneContent.split('\n');

  for (let i = 0; i < importLines.length; i++) {
    const parts = parseSourceImportLine(importLines[i]);
    if (!parts) { continue; }
    if (resolveSourceImportNoExt(specDir, parts.rawModPath) !== sourceNoExt) { continue; }

    const nextLine = buildSourceImportLine(parts, coveredFunctions);
    if (nextLine === importLines[i]) { return specContent; }
    if (nextLine) {
      importLines[i] = nextLine;
    } else {
      importLines.splice(i, 1);
    }
    return (
      specContent.slice(0, importsStart + SS_IMPORTS_START.length) +
      importLines.join('\n') +
      specContent.slice(importsEnd)
    );
  }

  if (coveredFunctions.length > 0) {
    log('Spec metadata repair: source-module import not found — import prune skipped');
  }
  return specContent;
}

function pruneGeneratedBlocksToFunctions(
  specContent: string,
  currentExports: string[],
  log: (msg: string) => void
): string {
  const { startIdx, endIdx, innerContent } = readMarker(specContent);
  if (startIdx === -1 || endIdx === -1) { return specContent; }

  const lines = innerContent.split('\n');
  const keptLines: string[] = [];
  const dropped: string[] = [];
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();

    if (!trimmed.startsWith('describe(') && !trimmed.startsWith('describe.')) {
      keptLines.push(line);
      i++;
      continue;
    }

    const block: string[] = [];
    let braceDepth = 0;
    let j = i;
    for (; j < lines.length; j++) {
      const blockLine = lines[j];
      block.push(blockLine);
      braceDepth += (blockLine.match(/\{/g) ?? []).length;
      braceDepth -= (blockLine.match(/\}/g) ?? []).length;
      if (braceDepth === 0) {
        j++;
        break;
      }
    }

    if (describeLineMatchesAnyFunction(line, currentExports)) {
      keptLines.push(...block);
    } else {
      dropped.push(trimmed);
      while (keptLines.length > 0 && keptLines[keptLines.length - 1].trim() === '') {
        keptLines.pop();
      }
    }
    i = j;
  }

  if (dropped.length === 0) { return specContent; }

  const marker = rebuildMarkerFromContent(specContent, currentExports) ?? { version: 1, covered: [], pending: [] };
  const nextInner = keptLines.join('\n').trim();
  const newBlock = nextInner
    ? [buildMarkerLine(marker), nextInner, SS_END].join('\n')
    : [buildMarkerLine(marker), SS_END].join('\n');
  log(`Spec metadata repair: pruned stale generated block(s) — ${dropped.length}`);
  return specContent.slice(0, startIdx) + newBlock + specContent.slice(endIdx);
}

// Replace the // Functions covered: header line so it matches the covered= marker list.
// Returns the updated content, or the original if the line is absent (logs a warning).
function updateFunctionsCoveredHeader(
  specContent: string,
  coveredFunctions: string[],
  log: (msg: string) => void
): string {
  if (!/^\/\/ Functions covered:/m.test(specContent)) {
    log('Gap append: // Functions covered: header line not found — header update skipped');
    return specContent;
  }
  return specContent.replace(
    /^\/\/ Functions covered:.*$/m,
    `// Functions covered: ${coveredFunctions.join(', ')}`
  );
}

export async function repairSpecMetadataForCoveredFunctions(
  sourcePath: string,
  currentExports: string[],
  log: (msg: string) => void
): Promise<SSMarker | null> {
  const specPath = await resolveSpecPath(sourcePath, log);
  if (!fs.existsSync(specPath)) { return null; }

  let content: string;
  try {
    const bytes = await vscode.workspace.fs.readFile(vscode.Uri.file(specPath));
    content = Buffer.from(bytes).toString('utf8');
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    log(`Spec metadata repair: read failed (${msg}) — skipping`);
    return null;
  }

  if (isUnmanagedContent(content)) { return null; }

  let repairedContent = pruneGeneratedBlocksToFunctions(content, currentExports, log);

  const repairedMarker = rebuildMarkerFromContent(repairedContent, currentExports);
  if (!repairedMarker) { return null; }

  repairedContent = updateMarkerOnly(repairedContent, repairedMarker);
  repairedContent = syncCoveredFunctionsImport(
    repairedContent,
    sourcePath,
    specPath,
    repairedMarker.covered,
    log
  );
  repairedContent = updateFunctionsCoveredHeader(repairedContent, repairedMarker.covered, log);

  if (repairedContent !== content) {
    await writeSpecFileToPath(specPath, repairedContent, log);
    log(`Spec metadata repaired — covered: [${repairedMarker.covered.join(', ')}]`);
  }

  return repairedMarker;
}

function escapeRegexLiteral(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function describeLineMatchesAnyFunction(line: string, functionNames: string[]): boolean {
  if (functionNames.length === 0) { return true; }
  const t = line.trim();
  if (!t.startsWith('describe(') && !t.startsWith('describe.')) { return false; }

  return functionNames.some(fn => {
    const pattern = new RegExp(
      `^describe(?:\\.\\w+)?\\s*\\(\\s*['"\`][^'"\`]*\\b${escapeRegexLiteral(fn)}\\b[^'"\`]*['"\`]`,
      'i'
    );
    return pattern.test(t);
  });
}

// ─── Gap batch append ─────────────────────────────────────────────────────────

export async function appendGapTests(
  sourcePath: string,
  newTests: string,
  updatedMarker: SSMarker,
  log: (msg: string) => void,
  allowedFunctions: string[] = []
): Promise<void> {
  const specPath = await resolveSpecPath(sourcePath, log);

  if (!fs.existsSync(specPath)) {
    log('Gap append: spec not found — skipping');
    return;
  }

  let specContent: string;
  try {
    const bytes = await vscode.workspace.fs.readFile(vscode.Uri.file(specPath));
    specContent = Buffer.from(bytes).toString('utf8');
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    log(`Gap append: could not read spec file (${msg}) — skipping`);
    return;
  }

  if (specContent.includes('<<<<<<<')) {
    log('Warning: Git conflict markers detected — skipping append');
    void vscode.window.showWarningMessage('SilentSpec: Resolve Git conflicts before regenerating.');
    return;
  }

  if (!specContent.includes(SS_START_PREFIX)) {
    log('Gap append: no SS-GENERATED block found — skipping');
    return;
  }

  const validationError = validateSSStructure(specContent);
  if (validationError) {
    log(`Gap append: SS structure invalid — ${validationError} — skipping`);
    return;
  }

  // Strip imports/helpers from gap output — only test blocks go into SS-GENERATED
  const rawLines = newTests
    .replace(/^\/\/ <SS-GENERATED-START[^\n]*\n/m, '')
    .replace(/\/\/ <SS-GENERATED-END>\s*$/m, '')
    .split('\n');

  const testLines: string[] = [];
  let capturing  = false;
  let keepBlock  = false;
  let braceDepth = 0;

  for (const line of rawLines) {
    const t = line.trim();

    if (!capturing) {
      if (t.startsWith('import ') || t.startsWith('vi.mock(') || t.startsWith('jest.mock(')) {
        continue;
      }
      if (t.startsWith('describe(') || t.startsWith('describe.')) {
        capturing  = true;
        keepBlock  = describeLineMatchesAnyFunction(line, allowedFunctions);
        braceDepth = 0;
      } else if (allowedFunctions.length === 0 && /(it|test)\s*\(/.test(t)) {
        capturing  = true;
        keepBlock  = true;
        braceDepth = 0;
      }
    }

    if (capturing) {
      if (keepBlock) { testLines.push(line); }
      braceDepth += (line.match(/\{/g) ?? []).length;
      braceDepth -= (line.match(/\}/g) ?? []).length;
      if (braceDepth === 0) {
        capturing  = false;
        keepBlock  = false;
        braceDepth = 0;
        if (testLines.length > 0 && testLines[testLines.length - 1] !== '') {
          testLines.push('');
        }
      }
    }
  }

  const cleanedTests = testLines.join('\n').trim();
  if (!cleanedTests) {
    log('Gap append: no test content after stripping imports/helpers — skipping');
    return;
  }

  const openBraces  = (cleanedTests.match(/\{/g) ?? []).length;
  const closeBraces = (cleanedTests.match(/\}/g) ?? []).length;
  if (openBraces !== closeBraces) {
    log(`Gap append: unbalanced braces (${openBraces} open, ${closeBraces} close) — skipping`);
    return;
  }

  const { startIdx, endIdx, innerContent } = readMarker(specContent);
  if (startIdx === -1 || endIdx === -1) {
    log('Gap append: readMarker returned invalid positions — skipping');
    return;
  }

  const combined = innerContent.trim()
    ? `${innerContent.trim()}\n\n${cleanedTests}`
    : cleanedTests;

  const newBlock = [buildMarkerLine(updatedMarker), combined, SS_END].join('\n');

  // Apply SS-IMPORTS update and // Functions covered: header update to a working copy.
  let workingContent = injectCoveredFunctionsIntoImports(
    specContent, sourcePath, specPath, updatedMarker.covered, log
  );
  workingContent = updateFunctionsCoveredHeader(workingContent, updatedMarker.covered, log);

  if (workingContent !== specContent) {
    // Content changed — recalculate SS-GENERATED positions in the updated content
    // and write everything in a single full-file write to keep positions consistent.
    const { startIdx: si, endIdx: ei } = readMarker(workingContent);
    if (si !== -1 && ei !== -1) {
      const finalContent = workingContent.slice(0, si) + newBlock + workingContent.slice(ei);
      await writeSpecFileToPath(specPath, finalContent, log);
    } else {
      // Marker positions lost after content update — fall back to SS-GENERATED-only splice
      log('Gap append: marker positions invalid after content update — writing SS-GENERATED only');
      await writeSpecFileToPath(specPath, specContent, log, { startIdx, endIdx, newBlock });
    }
  } else {
    // No content changes — use the original targeted splice (faster)
    await writeSpecFileToPath(specPath, specContent, log, { startIdx, endIdx, newBlock });
  }

  const markerSummary =
    `covered: [${updatedMarker.covered.join(', ')}]` +
    (updatedMarker.pending.length > 0 ? ` pending: [${updatedMarker.pending.join(', ')}]` : '');
  log(`Gap append complete — ${markerSummary}`);
}

// ─── Marker-only update ───────────────────────────────────────────────────────

export async function updateMarker(
  sourcePath: string,
  updatedMarker: SSMarker,
  log: (msg: string) => void
): Promise<void> {
  const specPath = await resolveSpecPath(sourcePath, log);
  if (!fs.existsSync(specPath)) { return; }

  try {
    const bytes = await vscode.workspace.fs.readFile(vscode.Uri.file(specPath));
    const content = Buffer.from(bytes).toString('utf8');
    const updated = updateMarkerOnly(content, updatedMarker);
    if (updated !== content) {
      await writeSpecFileToPath(specPath, updated, log);
      log(`Marker updated — covered: ${updatedMarker.covered.length}, pending: ${updatedMarker.pending.length}`);
    }
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : String(error);
    log(`Marker update: read failed (${msg}) — skipping`);
  }
}
